def fibonacci(n):
    if n <= 0:
        return "Input must be a positive integer"
    elif n == 1 or n == 2:
        return 1
    else:
        fib = [0] * (n + 1)
        fib[1], fib[2] = 1, 1
        for i in range(3, n+1):
            fib[i] = fib[i-1] + fib[i-2]
        return fib[n]

