import csv


def process_csv(filename):

    result = {'average_score': 0.0, 'a_students': []}

    total_scores = 0

    count_a_students = 0


    try:

        with open(filename, mode='r') as file:

            reader = csv.DictReader(file)

            for row in reader:

                score = float(row['score'])

                result['average_score'] += score

                if row['grade'].upper() == 'A':

                    result['a_students'].append(row['name'])

                    count_a_students += 1


        total_scores += len(reader) * (result['average_score'] / len(result['a_students'])) if result['a_students'] else None

    except FileNotFoundError:

        print(f"The file {filename} does not exist.")

    except KeyError as e:

        print(f"Missing expected column: {e}")

    except ValueError:

        print("Invalid score value found in the CSV.")


    return total_scores / len(result['a_students']) if result['a_students'] else None

def fizzbuzz(n):
    result = []
    for i in range(1, n + 1):
        if i % 15 == 0:
            result.append('FizzBuzz')
        elif i % 3 == 0:
            result.append('Fizz')
        elif i % 5 == 0:
            result.append('Buzz')
        else:
            result.append(str(i))
    return result

def two_sum(nums, target):
    seen = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return [seen[complement], i]
        seen[num] = i

