use strict;
use warnings;

my $filename = $ARGV[0];
open my $fh, '<', $filename or die "Could not open '$filename' $!";

my $total_lines = 0;
my $error_lines_count = 0;

while (my $line = <$fh>) {
    chomp($line);
    $total_lines++;

    if ($line =~ /error/i) {
        $error_lines_count++;
    }
}

close $fh;

print "$total_lines\n";
