using UnityEngine;

public class FirstPersonController : MonoBehaviour
{
    public float moveSpeed = 5f;
    public float turnSmoothTime = 2f;
    private float turnSmoothVelocity;

    void Update()
    {
        MovePlayer();
        LookAround();
    }

    void MovePlayer()
    {
        float h = Input.GetAxis("Horizontal");
        float v = Input.GetAxis("Vertical");

        Vector3 moveDir = new Vector3(h, 0f, v);
        transform.Translate(moveDir * Time.deltaTime * moveSpeed, Space.World);

        if (Input.GetButtonDown("Jump"))
            Jump();
    }

    void LookAround()
    {
        float h = Input.GetAxis("Mouse X");
        float v = -Input.GetAxis("Mouse Y");

        Quaternion yLook = Quaternion.Euler(0f, h * 60f * Time.deltaTime, 0f);
        transform.localRotation *= yLook;

        Vector3 lookDir = new Vector3(h, 0f, v) * moveSpeed;
        Camera.main.transform.rotation = Quaternion.Slerp(transform.rotation, yLook * transform.rotation, turnSmoothVelocity / turnSmoothTime);

        if (Input.GetButton("Horizontal")) { }
    }

    void Jump()
    {
        GetComponent<Rigidbody>().AddForce(new Vector3(0f, 5f, 0f), ForceMode.Impulse);
    }
}
